func billPageParams(f store.BillFilter) string {
	params := ""
	if f.Search != "" {
		params += "&q=" + f.Search
	}
	if f.Stage != "" {
		params += "&stage=" + f.Stage
	}
	if f.Category != "" {
		params += "&category=" + f.Category
	}
	if f.Chamber != "" {
		params += "&chamber=" + f.Chamber
	}
	if f.Level != "" {
		params += "&level=" + f.Level
	}
	if f.Province != "" {
		params += "&province=" + f.Province
	}
	if f.Sort != "" {
		params += "&sort=" + f.Sort
	}
	return params
}

func billsQueryString(f store.BillFilter) string {
	params := "per_page=" + strconv.Itoa(f.PerPage)
	if f.Search != "" {
		params += "&q=" + f.Search
	}
	if f.Stage != "" {
		params += "&stage=" + f.Stage
	}
	if f.Category != "" {
		params += "&category=" + f.Category
	}
	if f.Chamber != "" {
		params += "&chamber=" + f.Chamber
	}
	if f.Level != "" {
		params += "&level=" + f.Level
	}
	if f.Province != "" {
		params += "&province=" + f.Province
	}
	if f.Sort != "" {
		params += "&sort=" + f.Sort
	}
	return params
}

func billsURLWithSort(f store.BillFilter, sort string) string {
	g := f
	g.Sort = sort
	g.Page = 0
	return "/bills?" + billsQueryString(g)
}

func billsURLWithout(f store.BillFilter, field string) string {
	g := f
	g.Page = 0
	switch field {
	case "q":
		g.Search = ""
	case "stage":
		g.Stage = ""
	case "category":
		g.Category = ""
	case "chamber":
		g.Chamber = ""
	case "level":
		g.Level = ""
	case "province":
		g.Province = ""
	}
	return "/bills?" + billsQueryString(g)
}

func billChamberLabel(chamber string) string {
	switch chamber {
	case "commons":
		return "House"
	case "senate":
		return "Senate"
	}
	return chamber
}

func billLevelLabel(level string) string {
	switch level {
	case "federal":
		return "Federal"
	case "provincial":
		return "Provincial"
	}
	return level
}

